mutation {
  dashboardCreate(accountId: 123456, dashboard: {
    name: "Checkout Service Health"
    pages: [{
      name: "Overview"
      widgets: [{
        title: "Avg Duration"
        visualization: { id: "viz.line" }
        rawConfiguration: {
          nrqlQueries: [{
            accountId: 123456
            query: "SELECT average(duration) FROM Transaction WHERE appName = 'checkout-service' TIMESERIES"
          }]
        }
      }]
    }]
  }) {
    entityResult { guid }
  }
}
